import type { ScoreResult } from '../types';
import { invokeJudge } from './llmJudge';

export async function scoreMultiTypeRecognition(
  input: string,
  output: string
): Promise<ScoreResult> {
  const prompt = `You are an expert Contentful Data Architect evaluating an ETL pipeline.
Evaluate whether an AI agent correctly identified multiple distinct sections in the document and assigned each to the appropriate Content Type.

### INPUT PROVIDED TO THE AGENT (Markdown + Schema Definitions):
${input}

### ACTUAL OUTPUT GENERATED BY THE AGENT (Contentful JSON):
${output}

### EVALUATION CRITERION:
**Multi-Type Recognition:** Did the agent correctly identify when the document contained multiple distinct sections and assign EACH section to its own appropriate Content Type?
A single document can and should be split into multiple Content Types when the content warrants it.

Return ONLY valid JSON in this exact format (no markdown fences, no extra text):
{"score": <number 0.0–1.0>, "reason": "<1–2 sentences, noting any failures to split into multiple types>"}`;

  try {
    const { score, reason } = await invokeJudge(prompt);
    return { scorerId: 'multi-type-recognition', score, reason };
  } catch (err) {
    return { scorerId: 'multi-type-recognition', score: -1, reason: `Judge error: ${String(err)}` };
  }
}
